import { Worker } from 'bullmq';
import Redis from 'ioredis';

// Separate client — never reuse BullMQ's internal connection
const cache = new Redis({ host: 'localhost', port: 6379 });

const worker = new Worker('analytics', async (job) => {
  const key = `cache:analytics:${job.data.userId}`;

  const hit = await cache.get(key);
  if (hit) return JSON.parse(hit); // cache-aside: return early on hit

  const result = await computeAnalytics(job.data.userId);
  await cache.set(key, JSON.stringify(result), 'EX', 3600); // write-through
  return result;
}, { connection: { host: 'localhost', port: 6379 } });

